import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for NoWildcardImportsRule with ktlint_official code style.
 *
 * In ktlint_official code style, no wildcard imports are allowed by default (not even java.util.* or
 * kotlinx.android.synthetic.** which are allowed in intellij_idea and android_studio code styles).
 */
class NoWildcardImportsRuleKtlintOfficialCodeStyleTest {
    private val noWildcardImportsRuleAssertThat = assertThatRule { NoWildcardImportsRule() }

    @Nested
    inner class `Given ktlint_official code style` {
        @Test
        fun `Wildcard import for java_util is detected`() {
            val code =
                """
                import java.util.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasLintViolationWithoutAutoCorrect(1, 1, "Wildcard import")
        }

        @Test
        fun `Wildcard import for kotlinx_android_synthetic is detected`() {
            val code =
                """
                import kotlinx.android.synthetic.main.layout_name.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasLintViolationWithoutAutoCorrect(1, 1, "Wildcard import")
        }

        @Test
        fun `All wildcard imports are detected for ktlint_official code style`() {
            val code =
                """
                import java.util.*
                import kotlinx.android.synthetic.main.layout_name.*
                import some.other.package.*
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasLintViolationsWithoutAutoCorrect(
                    LintViolation(1, 1, "Wildcard import"),
                    LintViolation(2, 1, "Wildcard import"),
                    LintViolation(3, 1, "Wildcard import"),
                )
        }

        @Test
        fun `Non-wildcard imports are allowed for ktlint_official code style`() {
            val code =
                """
                import java.util.List
                import java.util.ArrayList
                """.trimIndent()
            noWildcardImportsRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
                .hasNoLintViolations()
        }
    }
}
"}

